CREATE VIEW `hour_consume_view` (`ad_name` COMMENT "广告名", `ad_id` COMMENT "广告id", `hour_consume_amt` COMMENT "近一小时消耗（投放）") AS (SELECT `res`.`ad_name`, `res`.`ad_id`, sum(CASE WHEN `res`.`is_now_hour` THEN `res`.`max_spend` ELSE (`res`.`max_spend` - `res`.`flag_spend`) END) AS `hour_consume_amt`
FROM (SELECT `res`.`ad_name`, `res`.`ad_id`, `res`.`date_start`, max(`res`.`spend_sum`) AS `max_spend`, max(CASE WHEN (`res`.`snap_time` < (date_sub(current_time(), INTERVAL 1 HOUR))) THEN `res`.`spend_sum` ELSE 0 END) AS `flag_spend`, CASE WHEN ((date_format(min(`res`.`snap_time`), '%Y-%m-%d %H:00:00')) = (date_format(current_time(), '%Y-%m-%d %H:00:00'))) THEN TRUE ELSE FALSE END AS `is_now_hour`
FROM (SELECT `dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`ad_name`, `dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`ad_id`, `dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`date_start`, `dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`snap_time`, sum(`dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`spend`) AS `spend_sum`
FROM `dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`
WHERE (((`dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`dt` >= (date_format(date_sub(current_time(), INTERVAL 1 HOUR), '%Y-%m-%d'))) AND (`dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`spend` > 0)) AND (`dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`date_start` >= (date_format(date_sub(current_time(), INTERVAL 1 HOUR), '%Y-%m-%d %H:00:00')))) AND (`dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`snap_time` <= (date_sub(current_time(), INTERVAL 30 MINUTE)))
GROUP BY `dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`ad_name`, `dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`ad_id`, `dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`date_start`, `dwd`.`dwd_advertisement_video_cn_dailyinsightbyhour_snap_view`.`snap_time`) `res`
GROUP BY `res`.`ad_name`, `res`.`ad_id`, `res`.`date_start`) `res`
GROUP BY `res`.`ad_name`, `res`.`ad_id`);
